    for (const [k, v] of Object.entries(obj)) {
      if (k === "mr_kowalski") {
        if (v && typeof v === "object") {
          if ("full_name" in v) v.full_name = "John Ronald Kowalski";
          else if ("name" in v) v.name = "John Ronald Kowalski";
          else obj[k] = { ...v, full_name: "John Ronald Kowalski" };
        } else {
          obj[k] = "John Ronald Kowalski";
        }
      } else if (v && typeof v === "object") {
        updateObj(v);
      }
    }
  }
}
